INSERT INTO public.theory_quiz_bank (course_id, question, reference_answer) VALUES
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does CRISP-DM stand for?', 'CRISP-DM stands for Cross-Industry Standard Process for Data Mining.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Why is CRISP-DM considered an industry-standard methodology?', 'It is considered an industry-standard methodology because it provides a structured, reliable, and proven framework for planning and executing data mining and data science projects. It is technology-neutral and can be applied across various industries.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'How many phases are there in the CRISP-DM model? Name them.', 'There are 6 phases: 1) Business Understanding, 2) Data Understanding, 3) Data Preparation, 4) Modeling, 5) Evaluation, and 6) Deployment.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the main goal of the Business Understanding phase?', 'The main goal is to understand the project objectives and requirements from a business perspective, and then convert this knowledge into a data mining problem definition and a preliminary plan.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'List three key tasks performed during the Business Understanding phase.', 'Three key tasks: 1) Determine business objectives, 2) Assess the situation (resources, requirements, risks), and 3) Define data mining goals (success criteria).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Define "Business Success Criteria" in this phase.', 'Business Success Criteria are the specific, measurable outcomes from the business perspective that will indicate the project has been successful (e.g., "Increase customer retention by 5%").'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the difference between the Business Understanding and Data Understanding phases?', 'Business Understanding focuses on the project''s goals and requirements from a business perspective. Data Understanding focuses on collecting, exploring, and verifying the data to see if it can meet those business goals.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the primary activity in the Data Understanding phase?', 'The primary activity is to get familiar with the data, identify data quality problems, and discover first insights.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is "initial data collection" in the context of Data Understanding?', '"Initial data collection" is the process of acquiring the data listed in the project resources, loading it into an analysis tool, and performing basic familiarization steps.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Describe "data description" as a step in Data Understanding.', '"Data description" involves examining the surface-level properties of the collected data, such as the format, number of records, number of fields, and basic statistics of each attribute.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "explore data" mean in the Data Understanding phase?', '"Explore data" means diving deeper into the data using queries, visualization, and reporting to address the data mining goals, test initial hypotheses, and uncover interesting patterns.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the purpose of "verify data quality" in this phase? What issues might be found?', 'The purpose is to check for data quality issues like missing values, invalid values, inconsistencies in coding, or outliers that could affect future modeling.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the main goal of the Data Preparation phase?', 'The main goal is to construct the final dataset from the raw data that will be fed into the modeling tool(s) in the next phase.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Why is the Data Preparation phase often the most time-consuming?', 'It is often the most time-consuming because it involves messy, manual, and iterative tasks like cleaning, integrating, and transforming data, which can take up to 80% of the project time.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "select data" mean in the Data Preparation phase?', '"Select data" involves deciding which data sources, tables, records, and attributes will be used for analysis, based on their relevance, quality, and technical constraints.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "clean data" entail in the Data Preparation phase?', '"Clean data" entails raising the data quality to the required level. This includes handling missing values, correcting errors, and resolving inconsistencies.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "construct data" mean? Give an example (feature engineering).', '"Construct data" involves creating new derived attributes or transforming existing ones. Example: Calculating BMI from height and weight (feature engineering).'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "integrate data" mean in this phase?', '"Integrate data" refers to combining information from multiple tables or sources to create a unified view of the data for modeling.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "format data" mean in this phase?', '"Format data" involves making syntactic changes to the data that are necessary for the specific modeling tool, such as converting string formats to a standard date format.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the main goal of the Modeling phase?', 'The main goal is to apply various modeling techniques to the prepared dataset to find patterns and build a model that best meets the business objectives.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'Why is "select modeling technique" an important first step in Modeling?', 'It is important because different modeling techniques have different assumptions and are suitable for different types of problems. Selecting the right technique sets the stage for success.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What does "generate test design" mean in the Modeling phase?', '"Generate test design" means creating a procedure to test the model''s quality and validity, often involving splitting the prepared dataset into training, validation, and test sets.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What happens during "build model"?', 'During "build model," one or more models are run on the prepared dataset using the selected technique, often involving setting specific parameters and calibrating the model.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the purpose of "assess model" from a technical perspective within this phase?', 'The purpose is to evaluate the model''s performance based on technical criteria (e.g., accuracy, MSE, ROC curve) and to rank the models built according to these metrics.'),
('203ee6ac-e5c8-4644-bb3c-855884ba8de4', 'What is the main goal of the Evaluation phase?', 'The main goal is to assess the model(s) in the context of the business objectives. It determines if the model meets the business success criteria and if it is good enough for deployment.');